index fc284bc61cce..631ca652d420 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -1161,6 +1161,47 @@ Value *InstCombinerImpl::SimplifyAddWithRemainder(BinaryOperator &I) {
     }
   }

+  // Match (X / C) * K + (X % C) -> (X / C) * (K - C) + X
+  Value *DivOpV, *RemOpV;
+  APInt DivC, RemC, MulC;
+  bool DivIsSigned, RemIsSigned;
+  auto MatchMulDivRem = [&](Value *MulSide, Value *RemSide) -> Value * {
+    // Match MulSide = (X / C) * K
+    Value *DivOperand;
+    if (!MatchMul(MulSide, DivOperand, MulC))
+      return nullptr;
+    // Check DivOperand matches X / C
+    if (!MatchDiv(DivOperand, DivOpV, DivC, DivIsSigned))
+      return nullptr;
+    // Match RemSide = X % C (same C and X as above)
+    if (!MatchRem(RemSide, RemOpV, RemC, RemIsSigned))
+      return nullptr;
+    // Check X matches and C matches
+    if (DivOpV != RemOpV || DivC != RemC || DivIsSigned != RemIsSigned)
+      return nullptr;
+    // K must be > C for the optimization to be profitable
+    if (MulC.ule(DivC))
+      return nullptr;
+    // Compute (K - C)
+    APInt NewMulC = MulC - DivC;
+    // Create new mul with nuw/nsw flags
+    Value *NewMul;
+    if (DivIsSigned) {
+      NewMul = Builder.CreateMul(DivOpV, ConstantInt::get(I.getType(), NewMulC),
+                                 "reass.mul");
+      cast<BinaryOperator>(NewMul)->setHasNoSignedWrap(true);
+    } else {
+      NewMul = Builder.CreateNUWMul(DivOpV, ConstantInt::get(I.getType(), NewMulC),
+                                    "reass.mul");
+    }
+    return Builder.CreateAdd(NewMul, RemOpV, "reass.add");
+  };
+
+  if (Value *Res = MatchMulDivRem(LHS, RHS))
+    return Res;
+  if (Value *Res = MatchMulDivRem(RHS, LHS))
+    return Res;
+
   return nullptr;
 }

@@ -1181,7 +1222,7 @@ static Instruction *canonicalizeLowbitMask(BinaryOperator &I,
   // Be wary of constant folding.
   if (auto *BOp = dyn_cast<BinaryOperator>(NotMask)) {
     // Always NSW. But NUW propagates from `add`.
-    BOp->setHasNoSignedWrap();
+    BOp->setHasNoSignedWrap(true);
     BOp->setHasNoUnsignedWrap(I.hasNoUnsignedWrap());
   }

